# --- Input validation utilities ---

def validate_string_input(value: str, field_name: str, max_length: int = 255, allow_empty: bool = False) -> str:
    """Validate and sanitize string input."""
    if not isinstance(value, str):
        raise ValueError(f"{field_name} must be a string")
    
    value = value.strip()
    
    if not allow_empty and not value:
        raise ValueError(f"{field_name} cannot be empty")
    
    if len(value) > max_length:
        raise ValueError(f"{field_name} exceeds maximum length of {max_length}")
    
    return value


def validate_id_input(value: str, field_name: str = "id") -> str:
    """Validate ID input - only allow expected format."""
    value = validate_string_input(value, field_name, max_length=50)
    
    # Allowlist: IDs should match expected pattern
    import re
    if not re.match(r'^[a-zA-Z0-9_-]+$', value):
        raise ValueError(f"Invalid {field_name} format")
    
    return value


def validate_pagination(first: Optional[int] = None, offset: Optional[int] = None) -> tuple:
    """Validate pagination parameters with safe defaults and limits."""
    max_page_size = 50
    default_page_size = 10
    
    if first is None:
        first = default_page_size
    elif not isinstance(first, int) or first < 1:
        first = default_page_size
    elif first > max_page_size:
        first = max_page_size
    
    if offset is None:
        offset = 0
    elif not isinstance(offset, int) or offset < 0:
        offset = 0
    
    return first, offset


