def _lookup_user_by_token(token: str) -> Optional[Dict[str, Any]]:
    """Securely look up a user by their API token using constant-time comparison."""
    token_hash = _hash_token(token)
    
    # Use constant-time comparison to prevent timing attacks
    for stored_hash, user_id in _hashed_token_map.items():
        if hmac.compare_digest(token_hash, stored_hash):
            user = USERS_DB.get(user_id)
            if user and user.get("is_active", False):
                return user
            return None
    
    return None


class AuthenticationMiddleware(BaseHTTPMiddleware):
    """Middleware that authenticates requests and sets current_user in request state."""
    
    async def dispatch(self, request: Request, call_next):
        request.state.current_user = None
        
        auth_header = request.headers.get("Authorization", "")
        
        if auth_header.startswith("Bearer "):
            token = auth_header[7:].strip()
            
            if token and len(token) <= 256:
                user = _lookup_user_by_token(token)
                if user:
                    # Store only necessary user info in request state
                    request.state.current_user = {
                        "id": user["id"],
                        "username": user["username"],
                        "role": user["role"],
                        "is_active": user["is_active"],
                    }
                    logger.info("User authenticated: %s", user["username"])
                else:
                    # Don't reveal whether token format was valid or user doesn't exist
                    logger.info("Authentication failed: invalid credentials")
            else:
                logger.info("Authentication failed: malformed token")
        
        response = await call_next(request)
        return response


# --- Authorization helpers ---

def get_current_user(info) -> Optional[Dict[str, Any]]:
    """Extract current user from GraphQL context."""
    request = info.context.get("request")
    if request and hasattr(request, "state"):
        return getattr(request.state, "current_user", None)
    return None


def require_authentication(resolver_func):
    """Decorator that requires authentication for a resolver."""
    @wraps(resolver_func)
    def wrapper(obj, info, *args, **kwargs):
        current_user = get_current_user(info)
        if not current_user:
            raise PermissionError("Authentication required")
        return resolver_func(obj, info, *args, **kwargs)
    return wrapper


def is_owner_or_admin(current_user: Dict[str, Any], target_user_id: str) -> bool:
    """Check if current user is the owner of the resource or an admin."""
    if not current_user:
        return False
    if current_user["role"] == "admin":
        return True
    return current_user["id"] == target_user_id


