# --- Query depth and complexity limiting ---

class QueryComplexityMiddleware:
    """Middleware to limit query depth and prevent abuse."""
    
    MAX_QUERY_DEPTH = 7
    MAX_QUERY_LENGTH = 4000  # Maximum query string length
    
    def resolve(self, next, obj, info, **kwargs):
        return next(obj, info, **kwargs)


def validate_query_complexity(query_string: str) -> bool:
    """Basic query complexity validation."""
    if not query_string or not isinstance(query_string, str):
        return False
    
    if len(query_string) > QueryComplexityMiddleware.MAX_QUERY_LENGTH:
        logger.warning("Query exceeds maximum length")
        return False
    
    # Basic depth check by counting nested braces
    max_depth = 0
    current_depth = 0
    for char in query_string:
        if char == '{':
            current_depth += 1
            max_depth = max(max_depth, current_depth)
        elif char == '}':
            current_depth -= 1
    
    if max_depth > QueryComplexityMiddleware.MAX_QUERY_DEPTH:
        logger.warning("Query exceeds maximum depth: %d", max_depth)
        return False
    
    # Block introspection in production
    if os.environ.get("ENVIRONMENT") == "production":
        if "__schema" in query_string or "__type" in query_string:
            logger.warning("Introspection query blocked in production")
            return False
    
    return True


# --- Custom GraphQL handler with query validation ---

async def graphql_handler(request: Request):
    """Custom GraphQL request handler with query validation."""
    if request.method == "POST":
        try:
            body = await request.json()
        except Exception:
            return JSONResponse(
                {"errors": [{"message": "Invalid JSON body"}]},
                status_code=400
            )
        
        query_string = body.get("query", "")
        
        if not validate_query_complexity(query_string):
            return JSONResponse(
                {"errors": [{"message": "Query validation failed"}]},
                status_code=400
            )
    
    # Delegate to Ariadne's GraphQL handler
    return await graphql_app.handle_request(request)


# --- Error formatter ---

def format_error(error, debug: bool = False):
    """Format GraphQL errors without leaking internal details."""
    formatted = error.formatted
    
    # In production, don't expose internal error details
    if not debug:
        # Remove extensions that might contain stack traces
        if "extensions" in formatted:
            del formatted["extensions"]
        
        # Sanitize error messages for known internal errors
        original = getattr(error, "original_error", None)
        if original and not isinstance(original, (ValueError, PermissionError)):
            formatted["message"] = "An internal error occurred"
            logger.error("Internal GraphQL error: %s", str(original))
    
    return formatted


